/* Temperature Sensor Driver - temp_sensor.h */
#ifndef TEMP_SENSOR_H
#define TEMP_SENSOR_H

#include <stdint.h>

#define TEMP_SENSOR_ADDR_DEFAULT  0x48U

typedef struct {
    uint8_t  i2c_bus;
    uint8_t  i2c_addr;
    uint8_t  resolution_bits;   /* 9, 10, 11, or 12 */
} TempSensor_Config_t;

/* Returns temperature in units of 0.1 degrees Celsius */
int16_t TempSensor_Read(void);

int  TempSensor_Init(TempSensor_Config_t *cfg);
void TempSensor_SetAlarmHigh(int16_t temp);
void TempSensor_SetAlarmLow(int16_t temp);
uint8_t TempSensor_GetAlarmStatus(void);
void TempSensor_Deinit(void);

#endif /* TEMP_SENSOR_H */

